public class ETG_CustBalanceList extends ETG_CustVendBalanceList
{
    ETG_CustTmpAccountSum custTmpAccountSum;

}

Method.Source:
void calculateDetails(CustVendTable _custTable)
{
    var query = new Query();

    query.addDataSource(tableNum(CustTable)).addRange(fieldNum(CustTable, AccountNum)).value(queryValue(_custTable.AccountNum));

    agingCalculation = this.constructAgingCalculation(new QueryRun(query));

    this.insertIntoTmpAccountSumV2(agingCalculation);
}

/// <summary>
///     Explicitly releases temp tables used in this class.
/// </summary>
/// <remarks>
///    Aging calculations create temp tables which are not released in a timely fashion.
///    The <c>releaseTempTables</c> method should to be called immediately after an aging calculations is completed and the results consumed.
/// </remarks>
public void releaseTempTables()
{
    custTmpAccountSum.dispose();
    agingPeriodScaleTmp.dispose();
}

public void calculateDetailsForMultiple(QueryRun _queryRun, Query _transactionQuery = null, boolean _withAmountCur = true, boolean _withAmountMst = true)
{
    agingCalculation = this.constructAgingCalculation(_queryRun, _transactionQuery);

    this.insertIntoTmpAccountSumV2(agingCalculation, _withAmountCur, _withAmountMst);
}

ETG_AccountSumMap calculateDetailsSrl(CustVendAC _accountNum)
{
    var query = new Query();

    query.addDataSource(tableNum(CustTable)).addRange(fieldNum(CustTable, AccountNum)).value(queryValue(_accountNum));

    agingCalculation = this.constructAgingCalculation(new QueryRun(query));

    this.insertIntoTmpAccountSumV2(agingCalculation, false, true);

    return tmpAccountSum;
}

protected CustVendAgingCalculation constructAgingCalculation(QueryRun _queryRun, Query _transactionQuery = null) { CustVendAgingCalculation custVendAgingCalculation = CustVendAgingCalculation::construct( SysModule::Cust, _queryRun, this.getAgedBy(), agingPeriodScaleTmp, transactionDate, agingBucketCount - 1, payments, printReversed, details, excludeZeroBalance, excludeNegativeBalance, null, NoYes::No, _transactionQuery);
custVendAgingCalculation.process();
return custVendAgingCalculation; }

/// <summary>
/// Gets the date which will be used to assign aging bucket to transaction.
/// </summary>
/// <returns>
/// Due date, Document date or Transaction date.
/// </returns>
protected DateTransactionDuedate getAgedBy()
{
    return DateTransactionDuedate::DueDate;
}

[SysObsolete('The insertIntoTmpAccountSum method is obsolete. Use the insertIntoTmpAccountSumV2 method instead.', false, 30\6\2020)] protected void insertIntoTmpAccountSum(CustVendAgingCalculation _agingCalculation, boolean _withAmountCur = true, boolean _withAmountMST = true, CustVendTable _toCustVendTable = null) { CustVendAgingCalculatedTmp agingCalculatedTmp = _agingCalculation.getAgingCalculated();
if (direction == ForwardBackwardPrinting::Backward || agingBucket == '') { update_recordSet agingCalculatedTmp setting BucketNumber = agingBucketCount - agingCalculatedTmp.BucketNumber where agingCalculatedTmp.BucketNumber != 0; }
var customers = agingCalculation.getCustVendTransAging();
insert_recordset custTmpAccountSum (AccountNum, CurrencyCode, InvoiceId, TransDate, Txt, Voucher, Name, GroupId) select AccountNum, CurrencyCode, InvoiceId, TransDate, Txt, Voucher from agingCalculatedTmp group by AccountNum, CurrencyCode, TransDate, InvoiceId, Voucher, Txt join Name, GroupId from customers group by Name, GroupId where agingCalculatedTmp.AccountNum == customers.AccountNum notexists join custTmpAccountSum // Avoid inserting a duplicate where custTmpAccountSum.AccountNum == agingCalculatedTmp.AccountNum && agingCalculatedTmp.CurrencyCode == custTmpAccountSum.CurrencyCode && agingCalculatedTmp.TransDate == custTmpAccountSum.TransDate && agingCalculatedTmp.InvoiceId == custTmpAccountSum.InvoiceId && agingCalculatedTmp.Voucher == custTmpAccountSum.Voucher && agingCalculatedTmp.Txt == custTmpAccountSum.Txt;
int withAmountCur = _withAmountCur; int withAmountMST = _withAmountMST;
#localmacro.updateBalance // accumulate from bucket %1 to balance %2 and the total balance (01) update_recordSet custTmpAccountSum setting Balance01 = custTmpAccountSum.Balance01 + agingCalculatedTmp.Amount * withAmountMST, Balance%2 = custTmpAccountSum.Balance%2 + agingCalculatedTmp.Amount * withAmountMST, Balance01Cur = custTmpAccountSum.Balance01Cur + agingCalculatedTmp.AmountCur * withAmountCur, Balance%2Cur = custTmpAccountSum.Balance%2Cur + agingCalculatedTmp.AmountCur * withAmountCur join agingCalculatedTmp where custTmpAccountSum.AccountNum == agingCalculatedTmp.AccountNum && agingCalculatedTmp.BucketNumber == %1 && agingCalculatedTmp.CurrencyCode == custTmpAccountSum.CurrencyCode && agingCalculatedTmp.TransDate == custTmpAccountSum.TransDate && agingCalculatedTmp.InvoiceId == custTmpAccountSum.InvoiceId && agingCalculatedTmp.Voucher == custTmpAccountSum.Voucher && agingCalculatedTmp.Txt == custTmpAccountSum.Txt; #endmacro
#updateBalance(1,02) #updateBalance(2,03) #updateBalance(3,04) #updateBalance(4,05) #updateBalance(5,06) #updateBalance(6,07)
tmpAccountSum = custTmpAccountSum;
_agingCalculation.releaseTempTables(); }

public ETG_AccountSumMap parmTmpAccountSum(ETG_AccountSumMap _tmpAccountSum, boolean _returnAmountMST = true)
{
    if (_returnAmountMST)
    {
        QueryRun qr = new QueryRun(this.buildParmTmpAccountSumQuery());
        qr.setCursor(custTmpAccountSum);

        qr.next();

        custTmpAccountSum = qr.get(tableNum(ETG_CustTmpAccountSum));

        this.setAccountSumMapBalanceFields(_tmpAccountSum);
        this.setAccountSumMapReportingCurrencyBalanceFields(_tmpAccountSum);
    }

    return _tmpAccountSum;
}

